    const int64_t kD = wShape->GetOriginShape().GetDim(2);
    const int64_t kH = wShape->GetOriginShape().GetDim(3);
    const int64_t kW = wShape->GetOriginShape().GetDim(4);

    // Fixed parameters for this kernel: stride=(1,1,1), padding=(0,0,0), dilation=(1,1,1), groups=1.
    const int64_t outD = D - kD + 1;
    const int64_t outH = H - kH + 1;
    const int64_t outW = W - kW + 1;

    const uint64_t totalPositions = static_cast<uint64_t>(N) * static_cast<uint64_t>(outD) *
                                    static_cast<uint64_t>(outH) * static_cast<uint64_t>(outW);

    // Choose a conservative blockDim based on totalPositions.
    uint32_t blockDim = static_cast<uint32_t>(totalPositions);
    if (blockDim == 0) blockDim = 1;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_n(static_cast<uint32_t>(N));
    tiling.set_cIn(static_cast<uint32_t>(Ci));
    tiling.set_d(static_cast<uint32_t>(D));
    tiling.set_h(static_cast<uint32_t>(H));
    tiling.set_w(static_cast<uint32_t>(W));

    tiling.set_cOut(static_cast<uint32_t>(Co));
    tiling.set_kD(static_cast<uint32_t>(kD));
    tiling.set_kH(static_cast<uint32_t>(kH));
    tiling.set_kW(static_cast<uint32_t>(kW));

    tiling.set_outD(static_cast<uint32_t>(outD));
    tiling.set_outH(static_cast<uint32_t>(outH));
    tiling.set_outW(static_cast<uint32_t>(outW));

    tiling.set_totalPositions(totalPositions);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

